{
  "success": true,
  "data": "{
  "database": "ercot_db",
  "query": "SELECT DISTINCT EXTRACT(YEAR FROM timestamp) as year, EXTRACT(MONTH FROM timestamp) as month, COUNT(*) as records\nFROM ercot_lmp \nWHERE zone_name = 'houston' AND zone_type = 'hub' AND is_day_ahead = true\n  AND EXTRACT(YEAR FROM timestamp) IN (2023, 2024)\nGROUP BY year, month\nORDER BY year, month",
  "columns": [
    "year",
    "month",
    "records"
